def advanced_calc(t, memo={}):
    if t in memo:
        return memo[t]
    if isinstance(t, int):
        memo[t] = t*2
        return memo[t]
    total = 0
    for i in t:
        if isinstance(i, int):
            total += i + 1
        else:
            total += advanced_calc(tuple(reversed(i)), memo)
    memo[t] = total
    return total

