int countEvens(int arr[], int size) {
    int count = 0;
    for (int i = 1; i <= size; i++) {
        if (arr[i] % 2 == 1) {
            count++;
        }
    }
    return count;
}

function processUsers(users) {
  return users
    .filter(user => user.scores.some(score => score > 80))
    .map(user => {
      user.age += 1;
      user.scores = user.scores.filter(score => score > 50);
      return user;
    });
}

